ylabel('Probability'); %[output:4bdf3e4d]
fig = figure(); %[output:46f63d4a]
t = tiledlayout(fig,1,1); %[output:46f63d4a]
ax = nexttile(t); %[output:46f63d4a]

histogram(ax, TimeInSystem, ... %[output:46f63d4a]
    'Normalization','probability', ... %[output:46f63d4a]
    'BinWidth', 1/12);   % 1 minute bins %[output:46f63d4a]

title(ax, "Time in system"); %[output:46f63d4a]
xlabel(ax, "Time (hours)"); %[output:46f63d4a]
ylabel(ax, "Probability"); %[output:46f63d4a]

