pause(2);
exportgraphics(fig, PictureFolder + filesep + "Time_in_system.pdf"); %[output:46f63d4a]

% ===== WAITING TIME (Wq) =====

fig = figure(); %[output:3eb1f3b1]
t = tiledlayout(fig,1,1); %[output:3eb1f3b1]
ax = nexttile(t); %[output:3eb1f3b1]

histogram(ax, WaitingInSystemSamples, ... %[output:3eb1f3b1]
    'Normalization','probability', ... %[output:3eb1f3b1]
    'BinWidth', 1/12); %[output:3eb1f3b1]

title(ax, "Waiting time in queue"); %[output:3eb1f3b1]
xlabel(ax, "Time (hours)"); %[output:3eb1f3b1]
